// Script Continued Below
//  RAJ STRY0063746 new functions called by server events to check document settings
// this keeps all of the code and logic in one place
var taskerDocumentScripts = Class.create();
taskerDocumentScripts.prototype = {
	initialize: function() {
	},

	// STRY0080196 - UIFormatter 
	isInstalled: function() {
		var result = {};
		result.activated = this.isActivated();
		var gr = new GlideRecord('sys_app_application');
		gr.addQuery('sys_name', 'DocIntegrator');
		gr.query();
		if(gr.next()){
			result.installed = true;
		}

		if (result.activated && result.installed ) {
			result.msg = gs.getMessage('Tasker - Docintegrator is Activated and Installed');
			result.code = 1;
		} else if (!result.activated && result.installed ) {			
			result.msg = gs.getMessage('Tasker - Docintegrator is Installed and Not Activated');
			result.code = 2;
		} else if (result.activated && !result.installed ) {
			result.msg = gs.getMessage('Tasker - DocIntegrator is Activated and Not Installed');
			result.code = 3;
		} else if (!result.activated && !result.installed ) {
			result.msg = gs.getMessage('Tasker - DocIntegrator is Not Activated and Not Installed');
			result.code = 4;			
		}
        gs.debug(gs.getMessage('Tasker - The DocIntegrator Settings for Tasker show - Result Code: {0} - Message: {1}',[result.code, result.msg]));
		if(result.code == 3){
			gs.error(gs.getMessage('Tasker - Error - DocIntegrator was activated in Tasker, but DocIntegrator is not installed on this system.') + gs.getMessage('Tasker - The DocIntegrator Settings for Tasker show - Result Code: {0} - Message: {1}',[result.code, result.msg]));
		}
		return result;
	},

	isActivated: function() {
		var result = this.getAttachmentSystemSettings().docIntDocumentsOn;
		// removed debug statements as isActivated is only called from the isInstalled function and the isInstalled function writes debug for the state of Docinetrator
		return result;
	},	

	// RAJ 2020.11.04  separate the code to just get system properties so it can be used with out a glide record.
	// Object - taskerDocumentSettings
	//	- taskerDocumentSettings.sNOWAttachmentsOn - true if the global setting for ServiceNow Attachments is on
	//	- taskerDocumentSettings.docIntDocumentsOn - true if DocInt Documents is on
	getAttachmentSystemSettings: function() {
		var systemSettingsUseAttachmentsorDocuments = {};
			var propertyUseAttachmentsorDocuments = gs.getProperty("x_153465_discovert.UseAttachmentsorDocuments");
			systemSettingsUseAttachmentsorDocuments.sNOWAttachmentsOn = (propertyUseAttachmentsorDocuments.startsWith("1") || propertyUseAttachmentsorDocuments.startsWith("3"));
			systemSettingsUseAttachmentsorDocuments.docIntDocumentsOn = (propertyUseAttachmentsorDocuments.startsWith("2") || propertyUseAttachmentsorDocuments.startsWith("3"));
		return systemSettingsUseAttachmentsorDocuments;

	},

	// RAJ 2020.03.22  STRY0063746 - this function takes different glide record types and returns the documents, attachments and shared values for that object
	// -------------------------------------------------------------------------------------------------------
	// Input Values
	// -------------------------------------------------------------------------------------------------------
	// gr - Glide Record
	//    Accepted glide records for this function (more could be added)
	//    Task - tableName == "x_153465_discovert_route_task_instance"
	//    Process Template - tableName == "x_153465_discovert_discover_routing_template"
	//    Process Template Task - tableName == "x_153465_discovert_route_tasks"
	// -------------------------------------------------------------------------------------------------------
	// Return Values
	// -------------------------------------------------------------------------------------------------------
	// Object - taskerDocumentSettings
	//	- taskerDocumentSettings.sNOWAttachmentsOn - true if the global setting for ServiceNow Attachments is on
	//  - taskerDocumentSettings.sharingAttachments - true if sharing Attachments is on
	//	- taskerDocumentSettings.docIntDocumentsOn - true if DocInt Documents is on
	//  - taskerDocumentSettings.sharingDocuments - true sharing Documents is on
	getAttachmentAndDocumentSettings: function(gr){
		var taskerDocumentSettings = {};
		taskerDocumentSettings.sNOWAttachmentsOn = false;
		taskerDocumentSettings.docIntDocumentsOn = false;
		taskerDocumentSettings.sharingAttachments = false;
		taskerDocumentSettings.sharingDocuments = false;

		var systemSettingsUseAttachmentsorDocuments = this.getAttachmentSystemSettings();
		taskerDocumentSettings.sNOWAttachmentsOn = systemSettingsUseAttachmentsorDocuments.sNOWAttachmentsOn == true;
		taskerDocumentSettings.docIntDocumentsOn = systemSettingsUseAttachmentsorDocuments.docIntDocumentsOn == true;
		if (gr.sys_id != -1){

			var tableName = gr.getRecordClassName();
			// if the glide record is a Task Instance, get the Shared Settings from the top task
			if (tableName == "x_153465_discovert_route_task_instance"){
				taskerDocumentSettings.sharingAttachments = (gr.u_top_task.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_top_task.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			if (tableName == "x_153465_discovert_task_tree"){
				taskerDocumentSettings.sharingAttachments = (gr.u_task_ref.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_task_ref.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// if the glide record is a Process Template, get the Shared Settings from the Process Template
			if (tableName == "x_153465_discovert_discover_routing_template"){
				taskerDocumentSettings.sharingAttachments = (gr.u_shared_attachments == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// if the glide record is a Process Template Task, get the Shared Settings from the Process Template Task's - Process Template
			if (tableName == "x_153465_discovert_route_tasks"){
				taskerDocumentSettings.sharingAttachments = (gr.tasker_process_definition.u_shared_attachments  == true && taskerDocumentSettings.sNOWAttachmentsOn == true);
				taskerDocumentSettings.sharingDocuments = (gr.tasker_process_definition.u_shared_documents  == true && taskerDocumentSettings.docIntDocumentsOn == true);
			}
			// RJ - PSD - STRY0064692 - first try to save documents to the Shared Documents folder for the Task Tree.
			if (tableName == "x_153465_discovert_suggested_taskers"){
				// just return value of sNOWAttachmentsOn for Suggested Taskers
				taskerDocumentSettings.sharingAttachments = taskerDocumentSettings.sNOWAttachmentsOn == true;
				// just return value of docIntDocumentsOn for Suggested Taskers
				taskerDocumentSettings.sharingDocuments = taskerDocumentSettings.docIntDocumentsOn == true;
			}
			// RJ first try to save documents to the Shared Documents folder for the Task Tree.
			if (tableName == "x_153465_discovert_discover_routing_runtime"){
				// just return value of sNOWAttachmentsOn for Suggested Taskers
				taskerDocumentSettings.sharingAttachments = taskerDocumentSettings.sNOWAttachmentsOn == true;
				// just return value of docIntDocumentsOn for Suggested Taskers
				taskerDocumentSettings.sharingDocuments = taskerDocumentSettings.docIntDocumentsOn == true;
			}

		}
		return taskerDocumentSettings;
	},


